#include<bits/stdc++.h>
using namespace std;
int n,m,x,y;
int dx[8]={2,2,1,-1,-2,-2,-1,1},dy[8]={-1,1,2,2,1,-1,-2,-2};
int dis[405][405];
int vis[405][405];
void bfs()
{
	queue<pair<int,int> >q;
	q.push({x,y});
	while(q.size()){
		int xx=q.front().first;
		int yy=q.front().second;
		q.pop();
		for(int i=0;i<8;i++){
			int X=xx+dx[i];
			int Y=yy+dy[i];
			if(X>0&&X<=n&&Y>0&&Y<=m&&!vis[X][Y]){
				vis[X][Y]=1;
				q.push({X,Y});
				dis[X][Y]=dis[xx][yy]+1;
			}
		}
	}
}
int main()
{
	memset(dis,-1,sizeof(dis));
	cin>>n>>m>>x>>y;
	dis[x][y]=0;
	vis[x][y]=1;
	bfs();
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cout<<dis[i][j]<<" ";
		}
		cout<<endl;
	}
}
